from collections import ChainMap

defaults = {'theme': 'light', 'lang': 'en', 'timeout': 30, 'retries': 3}
user_prefs = {'theme': 'dark', 'lang': 'fr'}
env_vars = {'timeout': 10}

config = ChainMap(env_vars, user_prefs, defaults)
print('theme:', config['theme'])
print('lang:', config['lang'])
print('timeout:', config['timeout'])
print('retries:', config['retries'])
print('total keys:', len(config))
